-- Prompt 31 server-enforced gates, accurate usage and non-destructive grace.
begin;set local role service_role;select set_config('request.jwt.claim.role','service_role',true);select public.upsert_stripe_billing_customer('30000000-0000-4000-8000-000000000001','cus_PlanGym123','billing@crux.example.invalid');select public.apply_stripe_subscription_event('evt_PlanEvent123','customer.subscription.created',false,'cus_PlanGym123','sub_PlanSubscription123','price_PlanPrice123','active',now(),now()+interval'30 days',false,null,null,'starter');
set local role authenticated;select set_config('request.jwt.claim.role','authenticated',true);select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000001',true);
do $$begin if public.has_feature_entitlement('30000000-0000-4000-8000-000000000001','chat')or public.has_feature_entitlement('30000000-0000-4000-8000-000000000001','analytics')then raise exception'Starter feature gate failed';end if;begin perform public.create_chat_channel('30000000-0000-4000-8000-000000000001','Blocked starter chat','',false);raise exception'Chat gate bypassed';exception when insufficient_privilege then null;end;if(select usage_value from public.get_plan_usage('30000000-0000-4000-8000-000000000001')where feature_key='staff_seats')<>3 then raise exception'Staff usage is inaccurate';end if;end$$;
set local role service_role;update public.subscriptions set plan_key='pro'where stripe_subscription_id='sub_PlanSubscription123';
set local role authenticated;select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000001',true);do $$begin if not public.has_feature_entitlement('30000000-0000-4000-8000-000000000001','chat')then raise exception'Pro chat was not enabled';end if;perform public.create_chat_channel('30000000-0000-4000-8000-000000000001','Pro test chat','',false);end$$;
set local role service_role;update public.subscriptions set status='past_due',current_period_end=now()where stripe_subscription_id='sub_PlanSubscription123';do $$declare before_count integer;begin select count(*)into before_count from public.routes where gym_id='30000000-0000-4000-8000-000000000001';if not private.feature_available('30000000-0000-4000-8000-000000000001','routes')then raise exception'Past-due grace was not applied';end if;update public.subscriptions set grace_ends_at=now()-interval'1 minute'where stripe_subscription_id='sub_PlanSubscription123';if private.feature_available('30000000-0000-4000-8000-000000000001','routes')then raise exception'Expired grace still enabled features';end if;if(select count(*)from public.routes where gym_id='30000000-0000-4000-8000-000000000001')<>before_count then raise exception'Downgrade deleted customer data';end if;end$$;
do $$declare first_grace timestamptz;begin update public.subscriptions set status='active'where stripe_subscription_id='sub_PlanSubscription123';update public.subscriptions set status='past_due',current_period_end=now()where stripe_subscription_id='sub_PlanSubscription123'returning grace_ends_at into first_grace;update public.subscriptions set current_period_end=now()+interval'1 day'where stripe_subscription_id='sub_PlanSubscription123';if(select grace_ends_at from public.subscriptions where stripe_subscription_id='sub_PlanSubscription123')<>first_grace then raise exception'Grace period was extended by a repeated webhook';end if;end$$;
rollback;
